import base64

# Decode /app/inbox response body
resp_b64 = ''
resp = base64.b64decode(resp_b64).decode('utf-8', 'replace')
body_start = resp.find('\r\n\r\n') + 4
body = resp[body_start:]
print('INBOX RESPONSE BODY:')
print(body)

# Decode the payload JWT inside
import json
data = json.loads(body)
for item in data:
    print('\nItem keys:', list(item.keys()))
    if 'payload' in item:
        payload_jwt = item['payload']
        print('Payload JWT:', payload_jwt)
        parts = payload_jwt.split('.')
        p = base64.urlsafe_b64decode(parts[1] + '==').decode()
        print('Payload decoded:', p)
